namespace sv_127bf8a1c27d427d9b8d7679f35c08d3;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public ThemeMode Mode { get; set; } = ThemeMode.Light;
    public string AccentColor { get; set; } = "#0d6efd";
}

using Microsoft.AspNetCore.Components;

namespace sv_127bf8a1c27d427d9b8d7679f35c08d3;

/// <summary>
/// Scoped service that holds mutable theme state per circuit.
/// Fires OnChange so subscribers can call StateHasChanged,
/// and pushes updates through CascadingValueSource so
/// [CascadingParameter] consumers also re-render.
/// </summary>
public class ThemeService
{
    private readonly CascadingValueSource<ThemeInfo> _source;

    public ThemeService(CascadingValueSource<ThemeInfo> source)
    {
        _source = source;
    }

    public ThemeInfo Current { get; private set; } = new();

    public event Action? OnChange;

    public async Task SetThemeModeAsync(ThemeMode mode)
    {
        Current.Mode = mode;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string color)
    {
        Current.AccentColor = color;
        await NotifyAsync();
    }

    public async Task ApplyAsync(ThemeInfo info)
    {
        Current = info;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        // Push to all [CascadingParameter] subscribers (crosses render-mode boundaries)
        await _source.NotifyChangedAsync(Current);
        // Notify scoped-service subscribers
        OnChange?.Invoke();
    }
}

