+@rendermode InteractiveServer
+@inject ThemeService ThemeSvc
+@implements IDisposable
+
+<PageTitle>Settings</PageTitle>
+
+<h2>User Preferences</h2>
+
+<div class="mb-3">
+    <label class="form-label fw-bold">Theme Mode</label>
+    <div>
+        @foreach (var mode in Enum.GetValues<ThemeMode>())
+        {
+            <label class="form-check form-check-inline">
+                <input class="form-check-input" type="radio" name="themeMode"
+                       checked="@(selectedMode == mode)"
+                       @onchange="() => SelectMode(mode)" />
+                @mode
+            </label>
+        }
+    </div>
+</div>
+
+<div class="mb-3">
+    <label class="form-label fw-bold">Accent Color</label>
+    <input type="color" class="form-control form-control-color"
+           value="@accentColor"
+           @onchange="OnAccentChanged" />
+    <small class="text-muted">@accentColor</small>
+</div>
+
+<div class="alert mt-3" style="border-left: 4px solid @accentColor;">
+    Preview: current theme is <strong>@selectedMode</strong> with accent
+    <span style="color: @accentColor;">@accentColor</span>.
+</div>
+
+@code {
+    private ThemeMode selectedMode;
+    private string accentColor = "#0d6efd";
+
+    protected override void OnInitialized()
+    {
+        selectedMode = ThemeSvc.Current.Mode;
+        accentColor = ThemeSvc.Current.AccentColor;
+        ThemeSvc.OnChange += OnThemeChanged;
+    }
+
+    private async Task SelectMode(ThemeMode mode)
+    {
+        selectedMode = mode;
+        await ThemeSvc.SetThemeModeAsync(mode);
+    }
+
+    private async Task OnAccentChanged(ChangeEventArgs e)
+    {
+        accentColor = e.Value?.ToString() ?? accentColor;
+        await ThemeSvc.SetAccentColorAsync(accentColor);
+    }
+
+    private void OnThemeChanged()
+    {
+        selectedMode = ThemeSvc.Current.Mode;
+        accentColor = ThemeSvc.Current.AccentColor;
+        InvokeAsync(StateHasChanged);
+    }
+
+    public void Dispose()
+    {
+        ThemeSvc.OnChange -= OnThemeChanged;
+    }
+}
+

